def decrypt_dash(ck: bytes, nonce: bytes, ciphertext: bytes, header: bytes) -> bytes:
    aesccm = AESCCM(ck, tag_length=8)
    return aesccm.decrypt(nonce, ciphertext, header)

def encrypt_dash(ck: bytes, nonce: bytes, plaintext: bytes, header: bytes) -> bytes:
    aesccm = AESCCM(ck, tag_length=8)
    return aesccm.encrypt(nonce, plaintext, header)
